/**
 * Run the recall eval harness against all three query strategies.
 *
 * Usage:
 *   pnpm exec tsx scripts/run-recall-eval.ts [--strategy raw|heuristic|llm|all]
 *
 * Loads data/recall-eval-set.json (generated by regenerate-recall-eval.ts).
 * For each entry, runs mnemon recall with the given strategy and measures whether
 * the expected fact appears in the top results. Outputs a comparison table.
 *
 * Gate threshold (per C4): Strategy C (llm) must win by ≥10pp over Strategy A (raw)
 * before an operator flips a group's query_strategy from 'raw' to 'llm'.
 *
 * Results written to data/recall-eval-results.json (gitignored).
 */
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';
import { spawn } from 'child_process';
import { homedir } from 'os';

import { DATA_DIR } from '../src/config.js';
import { extractFocusedQuery } from '../src/modules/memory/query-extractor.js';
import type { EvalEntry } from './regenerate-recall-eval.js';
import { loadEvalSet } from './regenerate-recall-eval.js';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const MNEMON_BIN = path.join(homedir(), '.local', 'bin', 'mnemon');
const DEFAULT_EVAL_SET_PATH = path.join(DATA_DIR, 'recall-eval-set.json');
const RESULTS_PATH = path.join(DATA_DIR, 'recall-eval-results.json');

export interface EvalResult {
  strategy: 'raw' | 'heuristic' | 'llm';
  recall_at_5: number;
  recall_at_10: number;
  mrr: number;
  total_entries: number;
  per_entry: Array<{
    fact_id: string;
    found_at_rank: number | null; // 1-indexed; null if not found in top-10
  }>;
}

export interface RecalledFact {
  id: string;
  content: string;
}

// Test seam — override the mnemon recall call.
type RecallFn = (agentGroupId: string, query: string) => Promise<RecalledFact[]>;
let _recallOverride: RecallFn | null = null;

export function setMnemonRecallForTest(fn: RecallFn | null): void {
  _recallOverride = fn;
}

export function _resetMnemonRecallForTest(): void {
  _recallOverride = null;
}

async function mnemonRecall(agentGroupId: string, query: string): Promise<RecalledFact[]> {
  if (_recallOverride !== null) {
    return _recallOverride(agentGroupId, query);
  }

  return new Promise<RecalledFact[]>((resolve) => {
    const args = ['recall', query, '--store', agentGroupId, '--limit', '10'];
    const child = spawn(MNEMON_BIN, args);
    let stdout = '';

    child.stdout.on('data', (chunk: Buffer) => {
      stdout += chunk.toString();
    });

    const timer = setTimeout(() => {
      child.kill('SIGTERM');
      resolve([]);
    }, 5_000);

    child.on('close', (code) => {
      clearTimeout(timer);
      if (code !== 0 || !stdout.trim()) {
        resolve([]);
        return;
      }
      try {
        const parsed = JSON.parse(stdout) as {
          results?: Array<{ insight?: { id?: string; content?: string } }>;
        };
        const facts = (parsed.results ?? [])
          .filter((r) => r.insight?.id)
          .map((r) => ({ id: r.insight!.id!, content: r.insight!.content ?? '' }));
        resolve(facts);
      } catch {
        resolve([]);
      }
    });

    child.on('error', () => {
      clearTimeout(timer);
      resolve([]);
    });
  });
}

// Heuristic query extractor (mirrors the logic in recall-injection.ts)
const STOPWORDS = new Set([
  'a', 'an', 'the', 'and', 'or', 'but', 'in', 'on', 'at', 'to', 'for', 'of',
  'with', 'by', 'from', 'up', 'about', 'into', 'through', 'during', 'is', 'are',
  'was', 'were', 'be', 'been', 'being', 'have', 'has', 'had', 'do', 'does',
  'did', 'will', 'would', 'could', 'should', 'may', 'might', 'must', 'can',
  'shall', 'that', 'this', 'these', 'those', 'it', 'its', 'i', 'me', 'my',
  'we', 'our', 'you', 'your', 'he', 'she', 'him', 'her', 'his', 'they',
  'them', 'their', 'what', 'which', 'who', 'when', 'where', 'why', 'how',
  'all', 'each', 'every', 'both', 'few', 'more', 'most', 'other', 'some',
  'such', 'no', 'not', 'only', 'same', 'so', 'than', 'too', 'very', 's', 't',
  'just', 'don', 'now', 'as', 'if', 'then', 'also', 'any', 'here', 'there',
  'out', 'one', 'two', 'new', 'get', 'use', 'make', 'like', 'see', 'know',
]);

function heuristicQuery(rawSlice: string): string {
  const lower = rawSlice.toLowerCase();
  const tokenRe = /[a-zA-Z0-9]+/g;
  const allTokens = rawSlice.match(tokenRe) ?? [];
  const lowerTokens = lower.match(tokenRe) ?? [];

  const seen = new Set<string>();
  const preferred: string[] = [];
  const fallback: string[] = [];

  for (let i = 0; i < lowerTokens.length; i++) {
    const lw = lowerTokens[i];
    if (STOPWORDS.has(lw) || lw.length < 2) continue;
    if (seen.has(lw)) continue;
    seen.add(lw);

    const original = allTokens[i] ?? lw;
    if (/[A-Z]/.test(original[0]) || /\d/.test(original)) {
      preferred.push(lw);
    } else {
      fallback.push(lw);
    }
  }

  return [...preferred, ...fallback].join(' ').slice(0, 80);
}

async function buildQuery(
  entry: EvalEntry,
  strategy: 'raw' | 'heuristic' | 'llm',
): Promise<string> {
  const raw = entry.expected_query;

  if (strategy === 'llm') {
    try {
      const q = await extractFocusedQuery(raw, raw, { timeoutMs: 800 });
      return q;
    } catch {
      // fall through to heuristic
    }
  }

  if (strategy === 'llm' || strategy === 'heuristic') {
    try {
      return heuristicQuery(raw);
    } catch {
      // fall through to raw
    }
  }

  return raw;
}

export async function runEvalForStrategy(
  entries: EvalEntry[],
  strategy: 'raw' | 'heuristic' | 'llm',
): Promise<EvalResult> {
  if (entries.length === 0) {
    return {
      strategy,
      recall_at_5: 0,
      recall_at_10: 0,
      mrr: 0,
      total_entries: 0,
      per_entry: [],
    };
  }

  const perEntry: Array<{ fact_id: string; found_at_rank: number | null }> = [];
  let hitAt5 = 0;
  let hitAt10 = 0;
  let reciprocalRankSum = 0;

  for (const entry of entries) {
    const query = await buildQuery(entry, strategy);
    const results = await mnemonRecall(entry.agent_group_id, query);

    let foundAtRank: number | null = null;
    for (let i = 0; i < results.length; i++) {
      if (results[i].id === entry.fact_id) {
        foundAtRank = i + 1; // 1-indexed
        break;
      }
    }

    perEntry.push({ fact_id: entry.fact_id, found_at_rank: foundAtRank });

    if (foundAtRank !== null) {
      if (foundAtRank <= 5) hitAt5++;
      if (foundAtRank <= 10) hitAt10++;
      reciprocalRankSum += 1 / foundAtRank;
    }
  }

  return {
    strategy,
    recall_at_5: entries.length > 0 ? hitAt5 / entries.length : 0,
    recall_at_10: entries.length > 0 ? hitAt10 / entries.length : 0,
    mrr: entries.length > 0 ? reciprocalRankSum / entries.length : 0,
    total_entries: entries.length,
    per_entry: perEntry,
  };
}

function printComparisonTable(results: EvalResult[]): void {
  console.log('\n=== Recall Eval Results ===\n');
  console.log('Strategy   | Recall@5 | Recall@10 | MRR    | N');
  console.log('-----------|----------|-----------|--------|----');
  for (const r of results) {
    const strat = r.strategy.padEnd(10);
    const r5 = (r.recall_at_5 * 100).toFixed(1).padStart(7) + '%';
    const r10 = (r.recall_at_10 * 100).toFixed(1).padStart(8) + '%';
    const mrr = r.mrr.toFixed(4).padStart(6);
    console.log(`${strat} | ${r5} | ${r10}  | ${mrr} | ${r.total_entries}`);
  }

  // Strategy C vs Strategy A comparison
  const raw = results.find((r) => r.strategy === 'raw');
  const llm = results.find((r) => r.strategy === 'llm');
  if (raw && llm) {
    const lift = (llm.recall_at_10 - raw.recall_at_10) * 100;
    console.log(`\n[Gate] LLM vs Raw lift on Recall@10: ${lift >= 0 ? '+' : ''}${lift.toFixed(1)}pp`);
    if (lift >= 10) {
      console.log('[Gate] PASS — Strategy C wins by ≥10pp. Safe to flip query_strategy to llm.');
    } else {
      console.log('[Gate] HOLD — Strategy C does not yet win by ≥10pp. Keep query_strategy=raw.');
    }
  }
  console.log('');
}

async function main(): Promise<void> {
  const args = process.argv.slice(2);
  const strategyArg = args.find((a) => a !== '--strategy' && args[args.indexOf(a) - 1] === '--strategy');
  const explicitStrategy = strategyArg as 'raw' | 'heuristic' | 'llm' | 'all' | undefined;
  // Support both "--strategy all" and "--strategy=all" style
  const stratOption = args.find((a) => a.startsWith('--strategy'));
  let runStrategy: 'raw' | 'heuristic' | 'llm' | 'all' = 'all';
  if (stratOption) {
    const val = stratOption.includes('=') ? stratOption.split('=')[1] : args[args.indexOf(stratOption) + 1];
    if (['raw', 'heuristic', 'llm', 'all'].includes(val)) {
      runStrategy = val as typeof runStrategy;
    }
  }

  let entries: EvalEntry[];
  try {
    entries = loadEvalSet();
  } catch (err) {
    console.error(
      'Cannot load data/recall-eval-set.json — run regenerate-recall-eval.ts first.',
      String(err),
    );
    process.exit(1);
  }

  console.log(`Loaded ${entries.length} eval entries.`);
  console.log(`Running strategy: ${runStrategy}`);

  const strategies: Array<'raw' | 'heuristic' | 'llm'> =
    runStrategy === 'all' ? ['raw', 'heuristic', 'llm'] : [runStrategy as 'raw' | 'heuristic' | 'llm'];

  const results: EvalResult[] = [];
  for (const strat of strategies) {
    console.log(`\nRunning strategy=${strat}...`);
    const result = await runEvalForStrategy(entries, strat);
    results.push(result);
  }

  printComparisonTable(results);

  // Write audit log (gitignored).
  const auditLog = { runAt: new Date().toISOString(), results };
  const tmpPath = `${RESULTS_PATH}.tmp`;
  try {
    fs.writeFileSync(tmpPath, JSON.stringify(auditLog, null, 2), 'utf8');
    fs.renameSync(tmpPath, RESULTS_PATH);
    console.log(`Audit log written to data/recall-eval-results.json`);
  } catch (err) {
    console.warn(`[warn] Could not write results file: ${String(err)}`);
  }
}

if (process.argv[1] && path.resolve(process.argv[1]) === path.resolve(fileURLToPath(import.meta.url))) {
  main().catch((err) => {
    console.error('Fatal:', err);
    process.exit(1);
  });
}
